import React, { forwardRef } from 'react';
import type { ButtonProps, ButtonRefType } from './ButtonBase';
import { ButtonBase } from './ButtonBase';
import { pickIconButtonProps, IconButton } from './IconButton';

export * from './ButtonBase';
export * from './IconButton';

const ButtonComp = forwardRef<ButtonRefType, ButtonProps>((props, ref) => {
  if (props.type === 'icon') {
    return <IconButton {...pickIconButtonProps(props)} size={props.size} ref={ref} />;
  }
  return <ButtonBase {...props} ref={ref} />;
});
type ButtonType = typeof ButtonComp & { __UD_BUTTON: boolean };

export const Button = ButtonComp as ButtonType;

Button.__UD_BUTTON = true;

if (__DEV__) {
  Button.displayName = 'Button';
}
